import numpy as np
from scipy.optimize import curve_fit
d=[l.replace(',','.').split() for l in open('graphene.dat')]
d=np.array([[float(a),float(b)] for a,b in d])
x,y=d[:,0],d[:,1]
i=np.argsort(x); x,y=x[i],y[i]
m=(x>=17000)&(x<=22000); xs,ys=x[m],y[m]
def lor(t,t0,g,A,off): return off+A*g*g/((t-t0)**2+g*g)
def gau(t,t0,g,A,off): return off+A*np.exp(-(t-t0)**2/(2*g*g))
def voigt(t,t0,sg,gl,A,off):
    from scipy.special import wofz
    z=((t-t0)+1j*gl)/(sg*np.sqrt(2)); return off+A*np.real(wofz(z))/np.real(wofz(1j*gl/(sg*np.sqrt(2))))
def tryfit(f,t,p0):
    p,_=curve_fit(f,t,ys,p0=p0,maxfev=200000); r=ys-f(t,*p); return np.sqrt(np.mean(r**2)),p
for p in [0.5,1,1.5,2,-1]:
    t=xs**p if p>0 else 1/xs
    t0=19196.0**p if p>0 else 1/19196.0
    try:
        rms,pp=tryfit(lor,t,[t0,abs(t0)*0.02,75000,11000]); print(f'lor t=x^{p} rms',round(rms))
    except Exception as e: print(p,e)
rms,pp=tryfit(gau,xs,[19196,450,75000,11000]); print('gauss rms',round(rms))
try:
    rms,pp=tryfit(voigt,xs,[19196,300,300,75000,11000]); print('voigt rms',round(rms),np.round(pp,1))
except Exception as e: print('voigt',e)
"
